fault_va = rcr2();  // read CR2 register
if (pid > 0 && fault_va < VM_USERLO) {
  // User process accessed invalid address
  pending_signals[pid] |= (1 << 11);
  return;  // DON'T kern_panic!
}

c = getchar();  // from console buffer
if (c == 0x03) {  // Ctrl+C character
  pending_signals[cur_pid] |= (1 << 2);
  return 0;  // return NULL to shell
}

if (pid <= 0 || pid >= NUM_IDS) return;
if (sig < 1 || sig >= NSIG) return;
pending_signals[pid] |= (1 << sig);
